import React, { createContext, useState, useContext } from 'react';

const DataContext = createContext(null);

export const DataProvider = ({ children }) => {
  // Khởi tạo danh sách nhân sự với dữ liệu mẫu
  const [staffList, setStaffList] = useState([
    { id: 1, username: 'nv1', password: '123', name: 'Nguyễn Văn A', role: 'staff' }
  ]);
  
  // Các trạng thái lưu trữ dữ liệu khác của hệ thống
  const [tasks, setTasks] = useState([]);
  const [attendanceLogs, setAttendanceLogs] = useState([]);
  const [facilityLogs, setFacilityLogs] = useState([]);

  // Hàm thêm nhân sự mới với ID duy nhất dựa trên thời gian
  const addStaff = (s) => setStaffList([...staffList, { ...s, id: Date.now() }]);

  // Hàm xóa nhân sự dựa trên ID (Đã được bổ sung theo yêu cầu của bạn)
  const deleteStaff = (id) => {
    setStaffList(staffList.filter(staff => staff.id !== id));
  };

  // Hàm khởi tạo/thêm công việc mới
  const addTask = (t) => setTasks([...tasks, { ...t, id: Date.now(), progress: 0 }]);

  // Hàm cập nhật tiến độ hoàn thành của công việc
  const updateTaskProgress = (id, p) => 
    setTasks(tasks.map(t => t.id === id ? { ...t, progress: p } : t));

  // Hàm ghi lại lịch sử điểm danh
  const addAttendance = (log) => setAttendanceLogs([...attendanceLogs, log]);

  // Hàm ghi lại báo cáo kiểm tra cơ sở vật chất
  const addFacilityLog = (log) => setFacilityLogs([...facilityLogs, log]);

  return (
    <DataContext.Provider value={{ 
      staffList, 
      addStaff, 
      deleteStaff, // Cung cấp hàm xóa cho StaffManager
      tasks, 
      addTask, 
      updateTaskProgress, 
      attendanceLogs, 
      addAttendance, 
      facilityLogs, 
      addFacilityLog 
    }}>
      {children}
    </DataContext.Provider>
  );
};

// Hook tùy chỉnh để sử dụng DataContext trong các component
export const useData = () => useContext(DataContext);
